try:

    # ==========================
    # Only From Reel Pool Channel
    # ==========================

    chat_id = str(message.chat.id)

    pool_channels = Bot.getData("reel_pool_channels")

    if pool_channels == None:
        pool_channels = ""

    allowed_channels = [i.strip() for i in pool_channels.split("\n") if i.strip() != ""]

    # Backward-compat: also allow the original single env-var channel
    try:
        if str(REEL_POOL_CHANNEL_ID) not in allowed_channels:
            allowed_channels.append(str(REEL_POOL_CHANNEL_ID))
    except:
        pass

    if chat_id not in allowed_channels:

        pass

    else:

        # ==========================
        # Only Video Content Captured
        # ==========================

        video = None

        try:
            video = message.video
        except:
            video = None

        if video == None or video == "None":

            pass

        else:

            file_id = video["file_id"]

            # ==========================
            # Get A Unique, Collision-Free Index (atomic)
            # This IS the running total count of the pool.
            # ==========================

            new_index = None

            try:

                add_result = libs.Resources.globalRes("reel_pool_total").add(1)

                if isinstance(add_result, dict):
                    new_index = add_result.get("value")

                if new_index == None:
                    new_index = libs.Resources.globalRes("reel_pool_total").value()

                new_index = int(new_index)

            except:

                new_index = None

            if new_index != None:

                # ==========================
                # Save Under Its Own Unique Key (race-proof)
                # ==========================

                Bot.saveData("reel_pool_item_" + str(new_index), file_id)

            else:

                # ==========================
                # Fallback (only if Resources system unavailable)
                # ==========================

                reel_pool = Bot.getData("reel_pool")

                if reel_pool == None:
                    reel_pool = ""

                if reel_pool.strip() == "":
                    reel_pool = file_id
                else:
                    reel_pool = reel_pool.strip() + "\n" + file_id

                Bot.saveData("reel_pool", reel_pool.strip())

            # ==========================
            # Atomic Batch Counter (for the log message only)
            # ==========================

            batch_count = 0

            try:
                libs.Resources.globalRes("reel_log_batch_count").add(1)
                batch_count = libs.Resources.globalRes("reel_log_batch_count").value()
            except:
                batch_count = Bot.getData("reel_log_batch_count")
                if batch_count == None:
                    batch_count = 0
                batch_count = int(batch_count) + 1
                Bot.saveData("reel_log_batch_count", batch_count)

            # ==========================
            # Debounced Log: cancel previous timer, schedule new one
            # ==========================

            old_job_id = Bot.getData("reel_log_job_id")

            if old_job_id != None:

                try:
                    Bot.cancelScheduledTask(old_job_id)
                except:
                    pass

            job = Bot.runCommandAfter(5, "send_reel_pool_log_summary")

            Bot.saveData("reel_log_job_id", job.get("id"))

except Exception as e:

    Bot.sendMessage(
        "<b>Handler Channel Post Error</b>\n\n<code>{}</code>".format(str(e)),
        chat_id=ADMIN_ID,
        parse_mode="HTML"
    )
